def resolve_model_path() -> str:
    env_model_path = os.getenv("MODEL_PATH", "").strip()
    candidates = []
    if env_model_path:
        candidates.append(Path(env_model_path))
    candidates.append(BASE_FOLDER / "viral_clip_detector")
    candidates.append(BASE_FOLDER.parent / "viral_clip_detector")

    for candidate in candidates:
        if candidate.exists():
            return str(candidate)

    return str(candidates[0])


