def resolve_ffmpeg_bin() -> str:
    custom = os.getenv("FFMPEG_BIN", "").strip()
    if custom:
        return custom
    if imageio_ffmpeg is not None:
        try:
            return imageio_ffmpeg.get_ffmpeg_exe()
        except Exception:
            pass
    return "ffmpeg"


FFMPEG_BIN = resolve_ffmpeg_bin()

def resolve_ffprobe_bin(ffmpeg_bin: str) -> str:
    ffmpeg_path = Path(ffmpeg_bin)
    expected_name = "ffprobe.exe" if os.name == "nt" else "ffprobe"
    if ffmpeg_path.exists():
        candidate = ffmpeg_path.with_name(expected_name)
        if candidate.exists():
            return str(candidate)
    return shutil.which(expected_name) or expected_name


FFPROBE_BIN = resolve_ffprobe_bin(FFMPEG_BIN)



def ensure_ffmpeg_in_path(ffmpeg_bin: str) -> None:
    ffmpeg_path = Path(ffmpeg_bin)
    if not ffmpeg_path.exists():
        return

    current_path = os.environ.get("PATH", "")
    path_items = current_path.split(os.pathsep) if current_path else []

    def prepend(entry: str) -> None:
        if entry and entry not in path_items:
            path_items.insert(0, entry)

    prepend(str(ffmpeg_path.parent))

    expected_name = "ffmpeg.exe" if os.name == "nt" else "ffmpeg"
    if ffmpeg_path.name != expected_name:
        shim_dir = Path(tempfile.gettempdir()) / "ffmpeg_shim"
        shim_dir.mkdir(parents=True, exist_ok=True)
        shim_path = shim_dir / expected_name

        if not shim_path.exists():
            try:
                if os.name == "nt":
                    shutil.copy2(ffmpeg_path, shim_path)
                else:
                    os.symlink(ffmpeg_path, shim_path)
            except Exception:
                try:
                    shutil.copy2(ffmpeg_path, shim_path)
                except Exception:
                    pass

        prepend(str(shim_dir))

    os.environ["PATH"] = os.pathsep.join(path_items)


ensure_ffmpeg_in_path(FFMPEG_BIN)


def resolve_js_runtime_args() -> List[str]:
    runtime_override = os.getenv("YTDLP_JS_RUNTIME", "").strip()
    if runtime_override:
        return ["--js-runtimes", runtime_override]

    candidates = []
    deno_from_path = shutil.which("deno")
    if deno_from_path:
        candidates.append(deno_from_path)

    py_bin_dir = Path(sys.executable).resolve().parent
    candidates.extend([str(py_bin_dir / "deno"), str(py_bin_dir / "deno.exe")])

    for cand in candidates:
        if cand and os.path.exists(cand):
            return ["--js-runtimes", f"deno:{cand}"]

    return []

