def download_youtube_video_with_yt_dlp(url: str, output_folder: str, filename: str) -> str:
    os.makedirs(output_folder, exist_ok=True)
    output_path = os.path.join(output_folder, filename)
    print(f"[+] Descargando video: {url} -> {output_path}")
    try:
        command = [
            sys.executable, "-m", "yt_dlp", "-f", "bestvideo+bestaudio/best",
            "--merge-output-format", "mp4", url, "-o", output_path
        ]
        subprocess.run(command, check=True)
        if os.path.exists(output_path):
            print("[OK] Descarga completada.")
            return output_path
        raise FileNotFoundError("yt-dlp no produjo el archivo esperado.")
    except FileNotFoundError:
        print("ERROR: 'yt-dlp' no encontrado. Instalala: pip install yt-dlp")
        sys.exit(1)
    except subprocess.CalledProcessError as e:
        print("ERROR: yt-dlp fallo:", e)
        sys.exit(1)


def get_media_duration_seconds(media_path: str) -> float:
    command = [
        FFPROBE_BIN,
        "-v", "error",
        "-show_entries", "format=duration",
        "-of", "default=noprint_wrappers=1:nokey=1",
        media_path,
    ]
    try:
        out = subprocess.check_output(command, stderr=subprocess.DEVNULL).decode("utf-8", errors="ignore").strip()
        return float(out) if out else 0.0
    except Exception:
        return 0.0


def _shift_word_timestamps(words: list, offset_s: float) -> list:
    shifted = []
    for w in words or []:
        w2 = dict(w)
        if w2.get("start") is not None:
            w2["start"] = float(w2["start"]) + offset_s
        if w2.get("end") is not None:
            w2["end"] = float(w2["end"]) + offset_s
        shifted.append(w2)
    return shifted


def _extract_audio_chunk_to_wav(video_path: str, chunk_wav: str, start_s: float, chunk_len_s: float) -> bool:
    try:
        subprocess.run(
            [
                FFMPEG_BIN,
                "-y",
                "-ss",
                f"{start_s:.3f}",
                "-t",
                f"{chunk_len_s:.3f}",
                "-i",
                video_path,
                "-vn",
                "-ar",
                "16000",
                "-ac",
                "1",
                chunk_wav,
            ],
            check=True,
            stdout=subprocess.DEVNULL,
            stderr=subprocess.DEVNULL,
        )
    except Exception:
        return False

    return os.path.exists(chunk_wav) and os.path.getsize(chunk_wav) >= 4096


def transcribe_audio_with_timestamps(video_path: str):
    if whisper is None:
        print("ERROR: Whisper no instalado. Instala con: pip install -U openai-whisper")
        sys.exit(1)

    print("[+] Cargando modelo Whisper:", WHISPER_SIZE)
    model = whisper.load_model(WHISPER_SIZE, device=DEVICE)

    segments = []
    duration_s = get_media_duration_seconds(video_path)
    use_known_duration = duration_s > 0.0
    use_word_timestamps = WHISPER_WORD_TIMESTAMPS

    if use_known_duration:
        print(f"[+] Duracion detectada: {duration_s/60:.1f} min")
    else:
        print("[!] No se pudo leer la duracion con ffprobe; transcripcion por chunks hasta EOF.")

    chunk_size_s = float(WHISPER_CHUNK_S)
    max_chunks = math.ceil(duration_s / chunk_size_s) if use_known_duration else WHISPER_MAX_CHUNKS
    start_s = 0.0
    chunk_idx = 0

    try:
        while chunk_idx < max_chunks:
            if use_known_duration and start_s >= duration_s:
                break

            chunk_idx += 1
            chunk_len_s = chunk_size_s if not use_known_duration else min(chunk_size_s, max(0.0, duration_s - start_s))
            if chunk_len_s <= 0:
                break

            chunk_wav = os.path.join(tempfile.gettempdir(), f"whisper_chunk_{os.getpid()}_{chunk_idx}.wav")
            try:
                ok = _extract_audio_chunk_to_wav(video_path, chunk_wav, start_s, chunk_len_s)
                if not ok:
                    if chunk_idx == 1:
                        print("ERROR: no se pudo extraer audio con ffmpeg para transcribir.")
                    break

                chunk_end = start_s + chunk_len_s
                total_chunks_label = str(max_chunks) if use_known_duration else "?"
                print(
                    f"[+] Transcribiendo chunk {chunk_idx}/{total_chunks_label}: "
                    f"{start_s/60:.1f}m - {chunk_end/60:.1f}m"
                )

                chunk_res = model.transcribe(
                    chunk_wav,
                    word_timestamps=use_word_timestamps,
                    verbose=WHISPER_VERBOSE,
                    condition_on_previous_text=False,
                    temperature=0,
                )
                chunk_segments = chunk_res.get("segments", [])

                if not chunk_segments and not use_known_duration:
                    break

                for seg in chunk_segments:
                    seg2 = dict(seg)
                    if seg2.get("start") is not None:
                        seg2["start"] = float(seg2["start"]) + start_s
                    if seg2.get("end") is not None:
                        seg2["end"] = float(seg2["end"]) + start_s
                    if "words" in seg2 and seg2.get("words"):
                        seg2["words"] = _shift_word_timestamps(seg2.get("words", []), start_s)
                    segments.append(seg2)
            finally:
                if os.path.exists(chunk_wav):
                    try:
                        os.remove(chunk_wav)
                    except Exception:
                        pass

            start_s += chunk_size_s
    finally:
        del model
        gc.collect()
        if DEVICE == "cuda":
            torch.cuda.empty_cache()

    print(f"[+] Transcripcion completada. {len(segments)} segmentos.")
    return segments


_CLIP_WHISPER_MODEL = None


def get_clip_whisper_model():
    global _CLIP_WHISPER_MODEL
    if _CLIP_WHISPER_MODEL is None:
        print("[+] Cargando Whisper para timestamps de clip:", WHISPER_SIZE)
        _CLIP_WHISPER_MODEL = whisper.load_model(WHISPER_SIZE, device=DEVICE)
    return _CLIP_WHISPER_MODEL


def transcribe_clip_words(clip_path: str) -> list:
    if whisper is None:
        return []
    try:
        model = get_clip_whisper_model()
        res = model.transcribe(
            clip_path,
            word_timestamps=True,
            verbose=False,
            condition_on_previous_text=False,
            temperature=0,
        )
        words = []
        for seg in res.get("segments", []) or []:
            for w in seg.get("words", []) or []:
                ws = w.get("start")
                we = w.get("end")
                word_text = str(w.get("word") or w.get("text") or "").strip()
                if ws is None or we is None or not word_text:
                    continue
                words.append({"start": float(ws), "end": float(we), "word": word_text})
        return words
    except Exception as e:
        print(f"[!] Fallo transcribiendo clip para timestamps: {e}")
        return []
