# 6) Prepare features y tokenización
# -----------------------------
def punctuation_restore_simple(text: str) -> str:
    qwords = ("who", "what", "when", "where", "why", "how", "is", "are", "do", "does", "did", "could", "would", "should")
    t = text.strip()
    if not t:
        return t
    if t[-1] not in ".!?":
        t = t + "."
    first_word = t.split()[0].lower().strip()
    if first_word in qwords:
        t = t[:-1] + "?"
    return t

def prepare_single_clip_for_inference(clip_data: dict, tokenizer: BertTokenizer) -> dict:
    text = punctuation_restore_simple(clip_data['transcription'])
    encoding = tokenizer.encode_plus(
        text, add_special_tokens=True, max_length=256,
        padding='max_length', truncation=True, return_attention_mask=True, return_tensors='pt'
    )
    wpm = clip_data.get('speech_rate_wpm', 0.0)
    emotions = clip_data.get('emotions', {})
    emotion_intensity = emotions.get('emotion_intensity', 1.0 - emotions.get('neutral', 0.0)) if emotions else clip_data.get('heur_emotion_intensity', 0.1)
    surprise_joy = emotions.get('surprise', 0.0) * emotions.get('joy', 0.0) if emotions else 0.0
    surprise_anger = emotions.get('surprise', 0.0) * emotions.get('anger', 0.0) if emotions else 0.0
    word_count = len(text.split())
    question_density = text.count('?') / max(word_count, 1)
    exclamation_density = text.count('!') / max(word_count, 1)
    raw = np.array([wpm, emotion_intensity, surprise_joy, surprise_anger, question_density, exclamation_density], dtype=np.float32)
    normalized = (raw - FEATURE_MEANS) / (FEATURE_STDS + 1e-9)
    feature_vector = torch.tensor(normalized.reshape(1, -1), dtype=torch.float).to(DEVICE)
    return {
        'input_ids': encoding['input_ids'].to(DEVICE),
        'attention_mask': encoding['attention_mask'].to(DEVICE),
        'features': feature_vector
    }

# -----------------------------
# 7) Dedupe sem simple (cosine greedy)
# -----------------------------
def dedupe_by_embeddings(clips: List[dict], embeddings: List[np.ndarray], threshold: float = 0.85) -> List[dict]:
    picked = []
    picked_embs = []
    for clip, emb in sorted(zip(clips, embeddings), key=lambda x: x[0]['viral_score'], reverse=True):
        keep = True
        for p_emb in picked_embs:
            cos = float(np.dot(emb, p_emb) / (np.linalg.norm(emb) * np.linalg.norm(p_emb) + 1e-9))
            if cos >= threshold:
                keep = False
                break
        if keep:
            picked.append(clip)
            picked_embs.append(emb)
        if len(picked) >= TOP_N_CLIPS:
            break
    return picked

# -----------------------------
# 8) ffmpeg extraction r
# -----------------------------
def ffmpeg_extract(input_path: str, output_path: str, start: float, end: float, recode=False):
    cmd = [FFMPEG_BIN, '-y', '-ss', str(start), '-to', str(end), '-i', input_path]
    if not recode:
        cmd += ['-c', 'copy', output_path]
    else:
        cmd += ['-c:v', 'libx264', '-preset', 'fast', '-crf', '23', '-c:a', 'aac', output_path]
    try:
        subprocess.run(cmd, check=True, stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL)
    except subprocess.CalledProcessError:
        subprocess.run([FFMPEG_BIN, '-y', '-ss', str(start), '-to', str(end), '-i', input_path, '-c:v', 'libx264', '-preset', 'fast', '-crf', '23', '-c:a', 'aac', output_path], check=True)

# -----------------------------
# 9) Carga del modelo y tokenizer con robustez
# -----------------------------
def ensure_model_safetensors(model_dir: Path) -> Path:
    weights_path = model_dir / "model.safetensors"
    if weights_path.exists() and weights_path.stat().st_size > 1024 * 1024:
        return weights_path

    chunks_dir = model_dir / "chunks"
    part_files = sorted(chunks_dir.glob("model.safetensors.part*")) if chunks_dir.exists() else []
    if not part_files:
        return weights_path

    print("[+] Reconstruyendo model.safetensors desde chunks...")
    with open(weights_path, "wb") as out_f:
        for part in part_files:
            with open(part, "rb") as in_f:
                shutil.copyfileobj(in_f, out_f)

    return weights_path


def load_model_and_tokenizer(model_path: str):
    print("[+] Cargando modelo y tokenizer...")
    model_dir = Path(model_path)
    weights_path = ensure_model_safetensors(model_dir)

    required_files = [
        "config.json",
        "vocab.txt",
        "tokenizer_config.json",
        "special_tokens_map.json",
    ]
    missing = [name for name in required_files if not (model_dir / name).exists()]
    if missing:
        print(
            "ERROR: faltan archivos del modelo entrenado en "
            f"{model_dir}. Faltan: {', '.join(missing)}"
        )
        print("ERROR: No se usaran pesos aleatorios. Debes desplegar tu modelo entrenado.")
        return None, None

    if not weights_path.exists():
        print(
            f"ERROR: no se encontro model.safetensors en {model_dir} "
            "ni chunks para reconstruirlo."
        )
        print("ERROR: No se usaran pesos aleatorios. Debes desplegar tu modelo entrenado.")
        return None, None

    try:
        tokenizer = BertTokenizer.from_pretrained(model_path, local_files_only=True)
        print("[+] Tokenizer cargado desde", model_path)
    except Exception as e:
        print(f"ERROR: no se pudo cargar tokenizer desde {model_path}: {e}")
        return None, None

    model = ViralClipModel()
    try:
        state_dict = load_file(str(weights_path), device=DEVICE)
        model.load_state_dict(state_dict, strict=False)
        print("[+] Pesos cargados desde model.safetensors")
    except Exception as e:
        print(f"ERROR: no se pudo cargar model.safetensors desde {weights_path}: {e}")
        return None, None

    model.to(DEVICE)
    model.eval()
    return model, tokenizer

# -----------------------------
# 10) Filtrado de solapamientos por interval overlap
# -----------------------------
def filter_overlapping_clips(ranked_clips: List[dict], num_clips: int, min_distance_s: float = 15.0) -> List[dict]:
    final = []
    for clip in ranked_clips:
        if len(final) >= num_clips:
            break
        s1, e1 = clip['start_time'], clip['end_time']
        overlapping = False
        for sel in final:
            s2, e2 = sel['start_time'], sel['end_time']
            if not (e1 + min_distance_s < s2 or s1 - min_distance_s > e2):
                overlapping = True
                break
        if not overlapping:
            final.append(clip)
    return final

# -----------------------------
# 11) MAIN: pipeline
# -----------------------------
def main(input_source: str):
    os.makedirs(OUTPUT_FOLDER, exist_ok=True)
    os.makedirs(CLIPS_OUTPUT_FOLDER, exist_ok=True)

    ts = time.strftime('%Y%m%d_%H%M%S')
    downloaded_filename = f"{ts}.mp4"

    input_source = (input_source or "").strip()
    using_local_file = os.path.isfile(input_source)

    if using_local_file:
        video_path = input_source
        print(f"[+] Usando archivo local: {video_path}")
    else:
        video_path = download_youtube_video_with_yt_dlp(input_source, OUTPUT_FOLDER, downloaded_filename)
        if not video_path or not os.path.exists(video_path):
            print("ERROR: no se pudo descargar el video.")
            sys.exit(1)

    segments = transcribe_audio_with_timestamps(video_path)
    if not segments:
        print("ERROR: No se pudieron obtener segmentos de transcripcion.")
        sys.exit(1)

    tmp_wav = os.path.join(tempfile.gettempdir(), f"audio_{ts}.wav")
    try:
        subprocess.run([FFMPEG_BIN, '-y', '-i', video_path, '-ar', '16000', '-ac', '1', tmp_wav], check=True, stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL)
    except subprocess.CalledProcessError as e:
        print("ERROR extrayendo audio:", e)
        sys.exit(1)

    duration_for_segmentation = float(segments[-1].get("end", 0.0)) if segments else 0.0
    can_use_energy = (
        ENABLE_ENERGY_SEGMENTATION
        and librosa is not None
        and duration_for_segmentation > 0
        and duration_for_segmentation <= MAX_ENERGY_SEGMENTATION_S
    )
    if ENABLE_ENERGY_SEGMENTATION and duration_for_segmentation > MAX_ENERGY_SEGMENTATION_S:
        print(f"[!] Skipping energy segmentation for long audio ({duration_for_segmentation/60:.1f} min)")
    dynamic_segments = compute_energy_segments(tmp_wav) if can_use_energy else []

    candidate_intervals = []
    if dynamic_segments:
        candidate_intervals = dynamic_segments
    else:
        duration = max(
            float(segments[-1].get("end", 0.0)) if segments else 0.0,
            get_media_duration_seconds(video_path),
        )
        if duration <= 0:
            print("ERROR: duracion del audio desconocida.")
            sys.exit(1)

        target_candidates = max(TOP_N_CLIPS * TARGET_CANDIDATE_MULTIPLIER, TOP_N_CLIPS)
        target_candidates = min(target_candidates, MAX_CANDIDATE_WINDOWS)

        if duration > CLIP_MAX_S and target_candidates > 1:
            adaptive_step = max(
                SLIDING_STEP_S,
                int(math.ceil((duration - CLIP_MAX_S) / float(target_candidates - 1))),
            )
        else:
            adaptive_step = SLIDING_STEP_S

        print(
            f"[+] Ventanas candidatas objetivo: <= {target_candidates} "
            f"(step adaptativo: {adaptive_step}s)"
        )

        cur = 0.0
        while cur < duration and len(candidate_intervals) < target_candidates:
            end = min(cur + CLIP_MAX_S, duration)
            candidate_intervals.append((cur, end))
            if end >= duration:
                break
            cur += adaptive_step
    if len(candidate_intervals) > MAX_CANDIDATE_WINDOWS:
        print(f"[!] Limitando ventanas candidatas a {MAX_CANDIDATE_WINDOWS} para estabilidad.")
        candidate_intervals = candidate_intervals[:MAX_CANDIDATE_WINDOWS]

    print("[+] Construyendo clips candidatos...")
    clips_candidates = []
    words_flat = []
    segment_spans = []

    for seg in segments:
        seg_start = float(seg.get("start", 0.0) or 0.0)
        seg_end = float(seg.get("end", seg_start) or seg_start)
        seg_text = str(seg.get("text", "") or "").strip()
        if seg_end > seg_start and seg_text:
            segment_spans.append((seg_start, seg_end, seg_text))

        for w in seg.get("words", []) or []:
            ws = w.get("start", w.get("t", None))
            we = w.get("end", None)
            word_text = str(w.get("word") or w.get("text") or "").strip()
            if ws is not None and we is not None and word_text:
                words_flat.append({"start": float(ws), "end": float(we), "word": word_text})

    preloaded_sound = None
    if ENABLE_PROSODY and parselmouth is not None:
        try:
            preloaded_sound = parselmouth.Sound(tmp_wav)
        except Exception:
            preloaded_sound = None

    use_word_windows = len(words_flat) > 0
    segment_spans.sort(key=lambda x: x[0])

    if use_word_windows:
        print(f"[+] Usando timestamps de palabras para candidatos ({len(words_flat)} palabras).")
        word_starts = [w["start"] for w in words_flat]
        seg_cursor = 0
    else:
        print("[!] Whisper sin word timestamps; usando ventanas por segmentos de texto (modo rapido).")
        word_starts = []
        seg_cursor = 0

    total_intervals = len(candidate_intervals)
    for idx, (s, e) in enumerate(candidate_intervals, start=1):
        if use_word_windows:
            i0 = bisect_left(word_starts, s)
            i1 = bisect_left(word_starts, e, lo=i0)
            words = [words_flat[i]["word"] for i in range(i0, i1)]
            text = " ".join(words).strip()
        else:
            while seg_cursor < len(segment_spans) and segment_spans[seg_cursor][1] <= s:
                seg_cursor += 1

            parts = []
            j = seg_cursor
            while j < len(segment_spans) and segment_spans[j][0] < e:
                ss, ee, txt = segment_spans[j]
                if ee > s:
                    parts.append(txt)
                j += 1

            text = " ".join(parts).strip()
        if not text:
            continue

        word_count = len(text.split())
        duration = max(1.0, e - s)
        wpm = (word_count / duration) * 60.0
        pros = extract_prosody_from_audio_segment(tmp_wav, s, e, preloaded_sound=preloaded_sound)
        heur_emotion_intensity = min(1.0, pros["intensity"] / 100.0 + (pros["pitch_std"] / 50.0))
        clip = {
            "start_time": float(s),
            "end_time": float(e),
            "transcription": text,
            "speech_rate_wpm": float(wpm),
            "prosody": pros,
            "heur_emotion_intensity": float(heur_emotion_intensity),
        }
        clips_candidates.append(clip)

        if idx % 200 == 0 or idx == total_intervals:
            print(f"[+] Progreso candidatos: {idx}/{total_intervals}")

    print(f"[+] {len(clips_candidates)} clips candidatos generados.")
    if not clips_candidates:
        print("ERROR: No se generaron clips candidatos.")
        sys.exit(1)

    model, tokenizer = load_model_and_tokenizer(MODEL_PATH)
    if model is None or tokenizer is None:
        print("ERROR cargando modelo/tokenizer.")
        sys.exit(1)

    print("[+] Evaluando candidatos con el modelo...")
    results = []
    for i in range(0, len(clips_candidates), INFERENCE_BATCH_SIZE):
        batch = clips_candidates[i:i + INFERENCE_BATCH_SIZE]
        inputs = [prepare_single_clip_for_inference(c, tokenizer) for c in batch]
        input_ids = torch.cat([x['input_ids'] for x in inputs], dim=0)
        attention_mask = torch.cat([x['attention_mask'] for x in inputs], dim=0)
        features = torch.cat([x['features'] for x in inputs], dim=0)
        with torch.no_grad():
            out = model(input_ids=input_ids, attention_mask=attention_mask, features=features)
            logits = out['logits']
            pooled = out.get('pooled_output', None)
            probs = torch.nn.functional.softmax(logits, dim=1).cpu().numpy()
            pooled_np = pooled.cpu().numpy() if pooled is not None else None
        for j, c in enumerate(batch):
            viral_score = float(probs[j][1]) if probs.shape[1] > 1 else float(probs[j][0])
            entry = {**c, 'viral_score': viral_score}
            entry['embedding'] = pooled_np[j] if pooled_np is not None else None
            results.append(entry)

    if not results:
        print("ERROR: No hubo resultados tras inference.")
        sys.exit(1)

    del model
    del tokenizer
    gc.collect()
    if DEVICE == "cuda":
        torch.cuda.empty_cache()

    results_sorted = sorted(results, key=lambda x: x['viral_score'], reverse=True)
    embeddings = [r['embedding'] for r in results_sorted if r.get('embedding') is not None]
    if embeddings:
        emb_norms = [e / (np.linalg.norm(e) + 1e-9) for e in embeddings]
        filtered = dedupe_by_embeddings([r for r in results_sorted if r.get('embedding') is not None], emb_norms, threshold=0.88)
        filtered_ids = set(id(x) for x in filtered)
        for r in results_sorted:
            if len(filtered) >= TOP_N_CLIPS:
                break
            if id(r) not in filtered_ids:
                filtered.append(r)
        top_clips = filtered[:TOP_N_CLIPS]
    else:
        top_clips = filter_overlapping_clips(results_sorted, TOP_N_CLIPS, min_distance_s=15.0)

    print(f"[+] Se seleccionaron {len(top_clips)} clips finales.")
    if not top_clips:
        print("ERROR: no se seleccionaron clips finales.")
        sys.exit(1)

    run_ts = time.strftime('%Y%m%d_%H%M%S')

    def save_sidecar_for_clip(clip_data, clip_start, clip_end, out_mp4_path):
        clip_duration = max(0.001, float(clip_end - clip_start))
        clip_words = []

        if words_flat and word_starts:
            i0 = bisect_left(word_starts, clip_start)
            i1 = bisect_left(word_starts, clip_end, lo=i0)
            for w in words_flat[i0:i1]:
                word_txt = str(w.get("word", "")).strip()
                if not word_txt:
                    continue
                ws = max(0.0, float(w["start"]) - clip_start)
                we = max(ws, float(w["end"]) - clip_start)
                if ws > clip_duration:
                    continue
                clip_words.append(
                    {
                        "start": round(ws, 3),
                        "end": round(min(we, clip_duration), 3),
                        "word": word_txt,
                    }
                )

        if not clip_words:
            if CLIP_WORD_TIMESTAMPS:
                words_from_clip = transcribe_clip_words(out_mp4_path)
                if words_from_clip:
                    for w in words_from_clip:
                        ws = max(0.0, float(w["start"]))
                        we = max(ws, float(w["end"]))
                        if ws > clip_duration:
                            continue
                        clip_words.append(
                            {
                                "start": round(ws, 3),
                                "end": round(min(we, clip_duration), 3),
                                "word": str(w.get("word", "")).strip(),
                            }
                        )

        if not clip_words:
            fallback_words = re.findall(r"\S+", str(clip_data.get("transcription", "")).strip())
            if fallback_words:
                per_word = clip_duration / max(len(fallback_words), 1)
                for wi, tok in enumerate(fallback_words):
                    ws = round(wi * per_word, 3)
                    we = round(min(clip_duration, (wi + 1) * per_word), 3)
                    clip_words.append({"start": ws, "end": max(ws + 0.05, we), "word": tok})

        segment_text = " ".join(w["word"] for w in clip_words).strip()
        sidecar_payload = {
            "start_time": float(clip_start),
            "end_time": float(clip_end),
            "viral_score": float(clip_data.get("viral_score", 0.0)),
            "segments": [
                {
                    "start": 0.0,
                    "end": round(clip_duration, 3),
                    "text": segment_text or str(clip_data.get("transcription", "")).strip(),
                    "words": clip_words,
                }
            ],
        }

        sidecar_path = os.path.splitext(out_mp4_path)[0] + ".json"
        with open(sidecar_path, "w", encoding="utf-8") as sf:
            json.dump(sidecar_payload, sf, ensure_ascii=False)

    for idx, clip in enumerate(top_clips):
        start = clip['start_time']
        end = clip['end_time']
        score = clip['viral_score']
        duration_for_end = float(segments[-1].get("end", 0.0)) if segments else end
        start = pick_natural_start(segments, start)
        end = pick_natural_end(segments, start, duration_for_end)
        if end <= start:
            end = min(start + CLIP_END_MIN_S, duration_for_end or (start + CLIP_END_MIN_S))
        dur = max(0.0, end - start)
        out_name = f"clip_{run_ts}_{idx+1}_s{int(start)}_e{int(end)}_score_{score:.3f}.mp4"
        out_path = os.path.join(CLIPS_OUTPUT_FOLDER, out_name)
        print(f"[>] Exportando clip {idx+1}: {start:.1f}s - {end:.1f}s  (score={score:.3f}) -> {out_path}")

        try:
            ffmpeg_extract(video_path, out_path, start, end, recode=False)
            print("[+] Clip exportado (copy).")
        except Exception as e:
            print("[!] Error exportando con -c copy, intentando recodificar:", e)
            ffmpeg_extract(video_path, out_path, start, end, recode=True)
            print("[+] Clip exportado (recode).")

        try:
            save_sidecar_for_clip(clip, start, end, out_path)
        except Exception as sidecar_error:
            print(f"[!] No se pudo escribir sidecar de subtitulos: {sidecar_error}")

    if not using_local_file:
        try:
            os.remove(video_path)
        except Exception:
            pass
    try:
        os.remove(tmp_wav)
    except Exception:
        pass

    print("[FIN] Pipeline completado.")
    # Salida exitosa
    sys.exit(0)

# -----------------------------
# entrypoint
# -----------------------------
if __name__ == "__main__":
    if len(sys.argv) > 1:
        url = sys.argv[1]
        print("[*] Iniciando pipeline para:", url)
        main(url)
    else:
        print("Uso: python seleccion_clip.py \"URL_O_RUTA_VIDEO\"")
        sys.exit(1)
